import Dexie, { type Table } from 'dexie';

export interface UserProfile {
  id?: number;
  name: string;
  age: number;
  gender: string;
  bloodGroup: string;
  height: string;
  weight: string;
  allergies: string[];
  conditions: string[];
  emergencyContact: string;
  avatar: string;
}

export interface Doctor {
  id?: number;
  name: string;
  specialization: string;
  degree: string;
  rating: number;
  fee: number;
  availability: string;
  status: 'online' | 'offline';
  image: string;
  experience: string;
  about: string;
  location: string;
  phone?: string;
}

export interface Appointment {
  id?: number;
  doctorId: number;
  date: string;
  time: string;
  type: 'visit' | 'virtual';
  status: 'upcoming' | 'completed' | 'cancelled';
  notes?: string;
}

export interface Medication {
  id?: number;
  name: string;
  dosage: string;
  frequency: string;
  times: string[];
  mealRelation: 'before' | 'after' | 'any';
  startDate: string;
  endDate: string;
  active: boolean;
}

export interface HealthMetric {
  id?: number;
  type: 'steps' | 'water' | 'heartRate' | 'sleep' | 'weight' | 'bp' | 'calories';
  value: number;
  unit: string;
  timestamp: number;
}

export interface LabReport {
  id?: number;
  testName: string;
  result: string;
  normalRange: string;
  date: string;
  note?: string;
}

export interface MedicalRecord {
  id?: number;
  title: string;
  type: 'Lab Report' | 'Prescription' | 'Visit' | 'Vaccination';
  date: string;
  doctorName?: string;
  description?: string;
  fileUrl?: string; // For future file upload support
  notes?: string;
}

export class HealthDatabase extends Dexie {
  userProfile!: Table<UserProfile>;
  doctors!: Table<Doctor>;
  appointments!: Table<Appointment>;
  medications!: Table<Medication>;
  healthMetrics!: Table<HealthMetric>;
  labReports!: Table<LabReport>;
  medicalRecords!: Table<MedicalRecord>;

  constructor() {
    super('HealthDatabase');
    this.version(3).stores({
      userProfile: '++id',
      doctors: '++id, specialization',
      appointments: '++id, doctorId, status, type',
      medications: '++id, active',
      healthMetrics: '++id, type, timestamp',
      labReports: '++id, date',
      medicalRecords: '++id, type, date'
    });
  }
}

export const db = new HealthDatabase();

export const runDb = async <T>(operation: () => Promise<T>): Promise<T | null> => {
  try {
    return await operation();
  } catch (error: any) {
    console.error('Database operation failed:', error);
    const message = error?.message || error?.name || 'Unknown database error';
    throw new Error(message);
  }
};

